import { Routes, Route, Navigate, useLocation } from 'react-router-dom';
import { HelmetProvider, Helmet } from 'react-helmet-async';
import { useState, useEffect } from 'react';
import Header from './components/layout/Header';
import Footer from './components/layout/Footer';
import AdminLogin from './pages/AdminLogin';
import AdminDashboard from './pages/AdminDashboard';
import PageBuilder from './pages/PageBuilder';
import DynamicPage from './pages/DynamicPage';
import MentionsLegales from './pages/MentionsLegales';
import PolitiqueConfidentialite from './pages/PolitiqueConfidentialite';
import authService from './services/authService';
import api from './services/api';

function AdminRoute({ children }) {
  useEffect(() => {
    if (!authService.isAuthenticated()) {
      window.location.href = '/login';
    } else if (!authService.isAdmin()) {
      window.location.href = '/login';
    }
  }, []);

  if (!authService.isAuthenticated() || !authService.isAdmin()) {
    return null;
  }

  return children;
}

function HomePage() {
  const [page, setPage] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api.get('/pages/home')
      .then(res => res.data)
      .then(pageData => {
        if (pageData && pageData.id) {
          setPage(pageData);
        }
        setLoading(false);
      })
      .catch(() => {
        setLoading(false);
      });
  }, []);

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-yellow-500"></div>
      </div>
    );
  }

  if (page && page.sections && page.sections.length > 0) {
    return (
      <>
        <Helmet>
          <title>{page.metaTitle || page.title || 'Assurance Décennale Électricien'}</title>
          {page.metaDescription && <meta name="description" content={page.metaDescription} />}
        </Helmet>
        <DynamicPage slug="home" />
      </>
    );
  }

  return (
    <>
      <Helmet>
        <title>Assurance Décennale Électricien | Devis Gratuit & Comparatif</title>
        <meta name="description" content="Obtenez votre assurance décennale pour electricien au meilleur prix. Devis gratuit et comparatif. RC Pro incluse. Réponse sous 24h. Obligatoire selon la loi Spinetta." />
        <meta name="keywords" content="assurance décennale, electrician, devis assurance, RC Pro, loi Spinetta, garantie décennale, assurance professionnel" />
        <meta name="robots" content="index, follow" />
        <meta property="og:title" content="Assurance Décennale Électricien | Devis Gratuit" />
        <meta property="og:description" content="Comparez les meilleures offres d'assurance décennale pour electricien. Devis gratuit en 2 minutes. RC Pro incluse." />
        <meta property="og:type" content="website" />
        <link rel="canonical" href="https://decennale-pro.fr/" />
      </Helmet>
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center p-8">
          <h1 className="text-2xl font-bold text-gray-800 mb-4">Site en cours de construction</h1>
          <p className="text-gray-600">Créez votre page d'accueil dans l'admin pour personnaliser ce site.</p>
          <a href="/admin/dashboard" className="inline-block mt-4 bg-yellow-500 text-white px-6 py-2 rounded-lg hover:bg-yellow-600">
            Accéder à l'admin
          </a>
        </div>
      </div>
    </>
  );
}

export default function App() {
  const location = useLocation();
  const isAdminPage = location.pathname === '/login' || location.pathname.startsWith('/admin');

  return (
    <HelmetProvider>
      <div className="min-h-screen overflow-x-hidden">
        {!isAdminPage && <Header />}
        <main className={isAdminPage ? '' : 'overflow-hidden'}>
          <Routes>
            <Route path="/" element={<HomePage />} />
            <Route path="/login" element={<AdminLogin />} />
            <Route 
              path="/admin/dashboard" 
              element={
                <AdminRoute>
                  <AdminDashboard />
                </AdminRoute>
              } 
            />
            <Route 
              path="/admin/page-builder" 
              element={
                <AdminRoute>
                  <PageBuilder />
                </AdminRoute>
              } 
            />
            <Route 
              path="/admin/page-builder/:pageId" 
              element={
                <AdminRoute>
                  <PageBuilder />
                </AdminRoute>
              } 
            />
            <Route path="/mentions-legales" element={<MentionsLegales />} />
            <Route path="/politique-confidentialite" element={<PolitiqueConfidentialite />} />
            <Route path="/:slug" element={<DynamicPage />} />
            <Route path="*" element={<Navigate to="/" replace />} />
          </Routes>
        </main>
        {!isAdminPage && <Footer />}
      </div>
    </HelmetProvider>
  );
}
